  using namespace sqlgen::literals;

  // Create database connection
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Build base query
  auto query = sqlgen::select_from<Book>("book_id"_c, "title"_c, "author"_c, "year"_c, "genre"_c, "price"_c);

  // Build WHERE conditions dynamically
  auto conditions = sqlgen::where(
    (filters.title_keyword && "title"_c.like("%" + *filters.title_keyword + "%")) ||
    (filters.min_year && "year"_c >= *filters.min_year) ||
    (filters.genre && "genre"_c == *filters.genre) ||
    (filters.max_price && "price"_c <= *filters.max_price)
  );

  // Apply conditions to query
  auto final_query = query | conditions;

  // Execute query and return results
  return final_query(conn).value();
}

}  // namespace query_search_books_by_criteria
