  }
  auto conn = conn_result.value();

  // 1. Add Grade column to Score table
  auto add_grade_result = conn->execute(
      "ALTER TABLE Score ADD COLUMN Grade CHAR(1) NOT NULL"
  );
  if (!add_grade_result) {
    // Handle execution error
    return;
  }

  // 2. Modify Age column in Student table to int with nullability
  // Note: This requires creating a new table and copying data
  auto create_temp_result = conn->execute(
      "CREATE TEMPORARY TABLE StudentTemp AS SELECT * FROM Student"
  );
  if (!create_temp_result) {
    return;
  }

  auto drop_student_result = conn->execute("DROP TABLE Student");
  if (!drop_student_result) {
    return;
  }

  auto create_new_student_result = conn->execute(
      "CREATE TABLE Student ("
      "SNo VARCHAR(10) PRIMARY KEY, "
      "SName VARCHAR(30), "
      "Sex INTEGER, "
      "Birthday DATETIME, "
      "Major INTEGER, "
      "Scorses REAL, "
      "Remark TEXT, "
      "Age INTEGER)"  // Modified to int with nullability
  );
  if (!create_new_student_result) {
    return;
  }

  auto insert_data_result = conn->execute(
      "INSERT INTO Student (SNo, SName, Sex, Birthday, Major, Scorses, Remark, Age) "
      "SELECT SNo, SName, Sex, Birthday, Major, Scorses, Remark, CAST(Age AS INTEGER) FROM StudentTemp"
  );
  if (!insert_data_result) {
    return;
  }

  auto drop_temp_result = conn->execute("DROP TABLE StudentTemp");
  if (!drop_temp_result) {
    return;
  }

  // 3. Drop Major table
