  if (!update2_result) {
    return false;
  }

  // 4. Verify changes persisted by reading the updated data
  // Read all accounts to verify updates
  auto read_result = (sqlgen::read<std::vector<Account>>)(conn);
  if (!read_result) {
    return false;
  }

  auto accounts = read_result.value();

  // Check if both updates were applied correctly
  bool update1_success = false;
  bool update2_success = false;

  for (const auto& acc : accounts) {
    if (acc.account_id == 1 && acc.balance == 1000.0 && acc.status == "active") {
      update1_success = true;
    }
    if (acc.account_id == 2 && acc.balance == 2000.0 && acc.status == "inactive") {
      update2_success = true;
    }
  }

