#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

namespace create_table_as_select {

struct Source {
  sqlgen::PrimaryKey<int> id;
  int value;
};

struct Target {
  int value;
};

/**
 * This function demonstrates creating a table from a select query.
 * Returns: query value.
 */
inline auto create_table_as_select() {
    using namespace sqlgen::literals;

    // Create select query from Source table, selecting value column
    auto select_query = sqlgen::select_from<Source>("value"_c);

    // Apply where condition: value > 100
    auto filtered_query = select_query | sqlgen::where("value"_c > 100);

    // Create table Target from the select query
    return sqlgen::create_as<Target>(filtered_query);
}

}  // namespace create_table_as_select
```

## Explanation:

1. **Select Query Construction**: 
   - `sqlgen::select_from<Source>("value"_c)` creates a SELECT query from the `Source` table, selecting only the `value` column using the string literal operator `_c`.

2. **Where Condition Application**:
   - `select_query | sqlgen::where("value"_c > 100)` applies the filter condition using the pipe operator `|` to chain the where clause.

3. **Table Creation**:
   - `sqlgen::create_as<Target>(filtered_query)` creates a CREATE TABLE AS SELECT statement that defines the `Target` table structure based on the filtered select query.

4. **Return Value**:
   - The function returns the query object, which can be executed against a database connection or converted to SQL using `sqlgen::sqlite::to_sql()`.

The implementation follows the exact sequence specified in the assessment objectives and uses the appropriate sqlgen functions and operators as documented in the reference materials.

